import argparse
import json
import os
import numpy as np
import heapq
from collections import deque

from cogniplan_env import ExplorationEnv


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n['coords'])] = i
    N = len(nodes)
    adj = [[] for _ in range(N + 1)]
    first_step_map = {}

    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get('coords', nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n['coords'], dtype=float) -
                    np.array(nodes[j]['coords'], dtype=float)
                ))
                if w > 0:
                    adj[i].append((j, w))

    r_idx = N
    for idx, nb in enumerate(neighbors):
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) - np.array(nb, dtype=float)
        ))
        if w > 0:
            adj[r_idx].append((j, w))
            adj[j].append((r_idx, w))
            first_step_map[j] = idx
    return adj, coord_to_idx, r_idx, first_step_map


class SimpleGreedyPlanner:
    def __init__(self, dist_denom=2.0, reverse_penalty=0.3,
                 history_penalty=0.5, history_len=5, persist_boost=1.05):
        self.dist_denom = float(dist_denom)
        self.reverse_penalty = float(reverse_penalty)
        self.history_penalty = float(history_penalty)
        self.history_len = int(history_len)
        self.persist_boost = float(persist_boost)
        self.reset()

    def reset(self):
        self.prev_pos = None
        self.last_nb_idx = None
        self.history = deque(maxlen=self.history_len)

    def plan(self, obs):
        robot_pos = np.array(obs['robot_pos'], dtype=float)
        nodes = obs['nodes']
        neighbors = obs['neighbors']
        frontiers = obs.get('frontiers', [])

        if not neighbors:
            self.prev_pos = robot_pos
            return None

        adj, coord_to_idx, r_idx, first_step_map = build_graph(
            nodes, robot_pos, neighbors
        )
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)
        history_set = set(self.history)

        def get_first_step(j):
            if prev[j] == r_idx:
                return j
            curr = j
            while prev[curr] is not None and prev[curr] != r_idx:
                curr = prev[curr]
                if curr is None:
                    return None
            return curr if prev[curr] == r_idx else None

        reverse_idx = None
        if self.prev_pos is not None:
            prev_vec = robot_pos - self.prev_pos
            prev_norm = np.linalg.norm(prev_vec)
            if prev_norm > 0.01:
                best_dot = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_vec = np.array(nb, dtype=float) - robot_pos
                    dot = np.dot(prev_vec, nb_vec)
                    if dot < best_dot:
                        best_dot = dot
                        reverse_idx = idx

        primary = {}
        secondary = {}
        tertiary = {}

        for j in range(N):
            if dist[j] == float('inf'):
                continue
            first = get_first_step(j)
            if first is None:
                continue
            nb_idx = first_step_map.get(first)
            if nb_idx is None:
                continue

            utility = float(nodes[j].get('utility', 0.0))
            d = dist[j]
            score = utility / (d + self.dist_denom)
            if j in history_set:
                score *= self.history_penalty

            if utility > 0:
                target = primary
            elif not nodes[j].get('visited', False):
                target = secondary
            else:
                target = tertiary

            if nb_idx not in target or score > target[nb_idx]:
                target[nb_idx] = score

        if not primary and not secondary and frontiers:
            frontiers_arr = [np.array(f, dtype=float) for f in frontiers]
            for j in range(N):
                if dist[j] == float('inf'):
                    continue
                first = get_first_step(j)
                if first is None:
                    continue
                nb_idx = first_step_map.get(first)
                if nb_idx is None:
                    continue
                node_coord = np.array(nodes[j]['coords'], dtype=float)
                min_fdist = min(
                    float(np.linalg.norm(node_coord - f)) for f in frontiers_arr
                )
                score = 1.0 / (min_fdist + 1.0)
                if j in history_set:
                    score *= self.history_penalty
                if nb_idx not in secondary or score > secondary[nb_idx]:
                    secondary[nb_idx] = score

        chosen = primary or secondary or tertiary
        if not chosen:
            self.prev_pos = robot_pos
            return tuple(neighbors[0]) if neighbors else None

        if self.last_nb_idx is not None and self.last_nb_idx in chosen:
            chosen[self.last_nb_idx] *= self.persist_boost
        if reverse_idx is not None and reverse_idx in chosen:
            chosen[reverse_idx] *= (1.0 - self.reverse_penalty)

        best_idx = max(chosen, key=chosen.get)

        target_coord = neighbors[best_idx]
        target_j = coord_to_idx.get(round_coord(target_coord))
        if target_j is not None:
            self.history.append(target_j)

        self.last_nb_idx = best_idx
        self.prev_pos = robot_pos.copy()
        return tuple(neighbors[best_idx])


def run_episode(env, planner):
    planner.reset()
    obs = env.reset()
    for _ in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get('done', False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    cfg_path = os.path.join(args.checkpoint, 'planner_cfg.json')
    cfg = {}
    if os.path.exists(cfg_path):
        with open(cfg_path) as f:
            cfg = json.load(f)

    planner = SimpleGreedyPlanner(**cfg)

    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    with open(eval_config_path) as f:
        eval_config = json.load(f)

    episodes = eval_config.get('episodes', [])
    if not episodes:
        maps_dir = os.path.join(args.data_path, 'maps_eval')
        for env_type in ['room', 'tunnel', 'outdoor']:
            subdir = os.path.join(maps_dir, env_type)
            if not os.path.isdir(subdir):
                continue
            for fname in sorted(os.listdir(subdir)):
                if fname.endswith('.png'):
                    episodes.append({
                        'map_path': os.path.join('maps_eval', env_type, fname),
                        'env_type': env_type
                    })

    per_episode = []
    per_type = {
        t: {'distances': [], 'explored_rates': [], 'successes': []}
        for t in ['room', 'tunnel', 'outdoor']
    }

    for ep in episodes:
        map_path = os.path.join(args.data_path, ep['map_path'])
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)
        success = 1 if metrics.get('success', False) else 0
        distance = float(metrics.get('travel_distance', 0.0))
        explored = float(metrics.get('explored_rate', 0.0))

        per_episode.append({
            'map_path': ep['map_path'],
            'env_type': ep.get('env_type', 'unknown'),
            'success': success,
            'travel_distance': distance,
            'explored_rate': explored
        })
        et = ep.get('env_type', 'unknown')
        if et in per_type:
            per_type[et]['distances'].append(distance)
            per_type[et]['explored_rates'].append(explored)
            per_type[et]['successes'].append(success)

    total_episodes = len(per_episode)
    explored_rate = (
        sum(e['explored_rate'] for e in per_episode) / total_episodes
        if total_episodes else 0.0
    )
    success_rate = (
        sum(e['success'] for e in per_episode) / total_episodes
        if total_episodes else 0.0
    )
    successful_distances = [
        e['travel_distance'] for e in per_episode if e['success']
    ]
    travel_distance = (
        sum(successful_distances) / len(successful_distances)
        if successful_distances else 0.0
    )

    per_type_out = {}
    for et, data in per_type.items():
        n = len(data['successes'])
        suc_dists = [
            d for d, s in zip(data['distances'], data['successes']) if s
        ]
        per_type_out[et] = {
            'explored_rate': (
                sum(data['explored_rates']) / n if n else 0.0
            ),
            'travel_distance': (
                sum(suc_dists) / len(suc_dists) if suc_dists else 0.0
            ),
            'success_rate': (
                sum(data['successes']) / n if n else 0.0
            )
        }

    result = {
        'explored_rate': explored_rate,
        'travel_distance': travel_distance,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type_out,
        'total_episodes': total_episodes
    }

    os.makedirs(os.path.dirname(args.output) or '.', exist_ok=True)
    with open(args.output, 'w') as f:
        json.dump(result, f, indent=2)

    print(
        f"Eval complete: {total_episodes} episodes, "
        f"success_rate={success_rate:.4f}, "
        f"travel_distance={travel_distance:.2f}, "
        f"explored_rate={explored_rate:.4f}"
    )


if __name__ == '__main__':
    main()
